#include <vector>
#include <queue>
#include <algorithm>
#include <climits>

using namespace std;

struct Edge {
    int v;
    long long cost;
    long long min_cost;
    Edge(int v, long long cost, long long min_cost) : v(v), cost(cost), min_cost(min_cost) {}
};

struct State {
    int u;
    long long total_cost;
    long long current_min;
    State(int u, long long total_cost, long long current_min) : u(u), total_cost(total_cost), current_min(current_min) {}
    bool operator<(const State& other) const {
        return total_cost > other.total_cost;
    }
};

long long solve(std::vector<std::vector<long long>> edges, std::vector<bool> online, long long k) {
    int n = online.size();
    vector<vector<Edge>> graph(n);
    for (const auto& e : edges) {
        int u = e[0], v = e[1];
        long long cost = e[2];
        graph[u].emplace_back(v, cost, cost);
    }

    priority_queue<State> pq;
    pq.emplace(0, 0, LLONG_MAX);
    long long max_score = -1;

    while (!pq.empty()) {
        State s = pq.top();
        pq.pop();
        int u = s.u;
        long long total_cost = s.total_cost;
        long long current_min = s.current_min;

        if (u == n - 1) {
            if (total_cost <= k) {
                if (current_min != LLONG_MAX) {
                    max_score = max(max_score, current_min);
                }
            }
            continue;
        }

        if (total_cost > k) {
            continue;
        }

        for (const Edge& e : graph[u]) {
            int v = e.v;
            if (v != n - 1 && !online[v]) {
                continue;
            }
            long long new_total = total_cost + e.cost;
            long long new_min = min(current_min, e.cost);
            pq.emplace(v, new_total, new_min);
        }
    }

    return max_score;
}

